// Regenerates src/scanner/fingerprint/bluetoothNumbers.generated.ts from the
// Nordic Semiconductor bluetooth-numbers-database — the maintained mirror of the
// Bluetooth SIG assigned numbers (company identifiers + GATT service UUIDs).
//
//   node scripts/generate-bluetooth-numbers.mjs
//
// Commit the regenerated file. It is intentionally checked in so the app carries
// the full dataset offline with no runtime dependency.
import { writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const BASE =
  'https://raw.githubusercontent.com/NordicSemiconductor/bluetooth-numbers-database/master/v1';
// Official Bluetooth SIG machine-readable assigned numbers (GAP Appearance).
const SIG_APPEARANCE_URL =
  'https://bitbucket.org/bluetooth-SIG/public/raw/main/assigned_numbers/core/appearance_values.yaml';
const OUT = join(
  dirname(fileURLToPath(import.meta.url)),
  '..',
  'src',
  'scanner',
  'fingerprint',
  'bluetoothNumbers.generated.ts'
);

async function fetchJson(name) {
  const res = await fetch(`${BASE}/${name}`);
  if (!res.ok) throw new Error(`Failed to fetch ${name}: ${res.status}`);
  return res.json();
}

// ble-plx exposes standard service UUIDs in the full 128-bit form built on the
// Bluetooth base UUID. Store the canonical short (16-bit) key so lookups work
// after normalising either form to its lowercase 16-bit hex.
function shortKey(uuid) {
  const lower = uuid.toLowerCase();
  const base = lower.match(/^0000([0-9a-f]{4})-0000-1000-8000-00805f9b34fb$/);
  if (base) return base[1];
  if (/^[0-9a-f]{4}$/.test(lower)) return lower;
  return lower; // vendor-specific 128-bit UUID kept verbatim
}

async function fetchText(url) {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch ${url}: ${res.status}`);
  return res.text();
}

// The appearance registry is a simple two-level YAML list; parse it with a
// line scanner rather than pulling in a YAML dependency. The full 16-bit
// appearance value is (category << 6) | subcategory.
function parseAppearanceYaml(yaml) {
  const entries = [];
  let category = null;
  let inSubcategory = false;
  let pendingValue = null;
  for (const rawLine of yaml.split('\n')) {
    const line = rawLine.replace(/#.*$/, '').trimEnd();
    const categoryMatch = line.match(/^ - category: (0x[0-9A-Fa-f]+)$/);
    if (categoryMatch) {
      category = { value: Number(categoryMatch[1]), name: null };
      inSubcategory = false;
      continue;
    }
    if (/^   subcategory:$/.test(line)) {
      inSubcategory = true;
      pendingValue = null;
      continue;
    }
    const subValueMatch = line.match(/^    - value: (0x[0-9A-Fa-f]+)$/);
    if (subValueMatch && inSubcategory) {
      pendingValue = Number(subValueMatch[1]);
      continue;
    }
    const nameMatch = line.match(/^ +name: (.+)$/);
    if (!nameMatch || !category) continue;
    const name = nameMatch[1].trim();
    if (inSubcategory && pendingValue !== null) {
      entries.push({
        value: (category.value << 6) | pendingValue,
        name: `${category.name} / ${name}`,
      });
      pendingValue = null;
    } else if (!inSubcategory) {
      category.name = name;
      entries.push({ value: category.value << 6, name });
    }
  }
  return entries;
}

const [companies, services, appearanceYaml] = await Promise.all([
  fetchJson('company_ids.json'),
  fetchJson('service_uuids.json'),
  fetchText(SIG_APPEARANCE_URL),
]);

const appearanceEntries = parseAppearanceYaml(appearanceYaml)
  .sort((a, b) => a.value - b.value)
  .map((entry) => `  ${entry.value}: ${JSON.stringify(entry.name)},`);

const companyEntries = companies
  .filter((c) => Number.isInteger(c.code) && typeof c.name === 'string')
  .sort((a, b) => a.code - b.code)
  .map((c) => `  ${c.code}: ${JSON.stringify(c.name)},`);

const seen = new Set();
const serviceEntries = [];
for (const s of services) {
  if (typeof s.uuid !== 'string' || typeof s.name !== 'string') continue;
  const key = shortKey(s.uuid);
  if (seen.has(key)) continue;
  seen.add(key);
  serviceEntries.push(`  ${JSON.stringify(key)}: ${JSON.stringify(s.name)},`);
}
serviceEntries.sort();

const banner = `// AUTO-GENERATED by scripts/generate-bluetooth-numbers.mjs — DO NOT EDIT BY HAND.
// Source: NordicSemiconductor/bluetooth-numbers-database (Bluetooth SIG assigned
// numbers). Regenerate with: node scripts/generate-bluetooth-numbers.mjs
`;

const contents = `${banner}
// Bluetooth SIG company identifiers keyed by their numeric assigned value.
export const BLE_COMPANY_NAMES: Record<number, string> = {
${companyEntries.join('\n')}
};

// GATT service names keyed by lowercase 16-bit UUID (or full 128-bit UUID for
// vendor-specific services). Look up via serviceName() which normalises input.
export const BLE_SERVICE_NAMES: Record<string, string> = {
${serviceEntries.join('\n')}
};

// GAP Appearance values (Bluetooth SIG assigned numbers) keyed by the full
// 16-bit value: (category << 6) | subcategory. Subcategory entries are named
// "Category / Subcategory"; bare-category entries have subcategory 0.
export const BLE_APPEARANCE_NAMES: Record<number, string> = {
${appearanceEntries.join('\n')}
};
`;

writeFileSync(OUT, contents);
console.log(
  `Wrote ${OUT}: ${companyEntries.length} companies, ${serviceEntries.length} services, ` +
    `${appearanceEntries.length} appearance values.`
);
